import{bV as e,aL as i,u as s,G as t}from"./chunks/framework.D_inzUUb.js";const k=JSON.parse('{"title":"办公与文件处理实用技巧","description":"","frontmatter":{"title":"办公与文件处理实用技巧","date":"2019-03-19T00:00:00.000Z","categories":["工具使用"],"tags":["Windows","Excel","批处理","文件处理"]},"headers":[],"relativePath":"posts/201903/19-merge-txt.md","filePath":"posts/201903/19-merge-txt.md","lastUpdated":1778811657000}'),l={name:"posts/201903/19-merge-txt.md"};function h(o,a,n,p,d,r){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="办公与文件处理实用技巧" tabindex="-1">办公与文件处理实用技巧 <a class="header-anchor" href="#办公与文件处理实用技巧" aria-label="Permalink to &quot;办公与文件处理实用技巧&quot;">​</a></h1><p>收集日常工作中的办公和文件处理小技巧，包括 Excel 公式和批处理脚本。</p><h2 id="合并同名-txt-文件" tabindex="-1">合并同名 txt 文件 <a class="header-anchor" href="#合并同名-txt-文件" aria-label="Permalink to &quot;合并同名 txt 文件&quot;">​</a></h2><blockquote><p>来源：<a href="https://github.com/aiastia/note/issues/30" target="_blank" rel="noreferrer">#30</a></p></blockquote><p>合并所有文件夹里的同名 txt 文件，并且把不同名的文件提取出来放到一起。</p><h3 id="方法" tabindex="-1">方法 <a class="header-anchor" href="#方法" aria-label="Permalink to &quot;方法&quot;">​</a></h3><p>自己弄个 <code>.bat</code> 批处理文件。新建一个记事本，把下面的内容贴进去，然后保存，把后缀名 <code>.txt</code> 改为 <code>.bat</code>。</p><div class="language-bat vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bat</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@echo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> off</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /r </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">%%i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (*.txt) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">%%i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">%%~ni</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">合并.tmp&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ren</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> *.tmp *.txt</span></span></code></pre></div><h3 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h3><ul><li><code>for /r</code> 递归遍历所有子目录中的 <code>.txt</code> 文件</li><li><code>%%~ni</code> 获取文件名（不含扩展名），同名文件内容会追加到同一个临时文件</li><li>最后将 <code>.tmp</code> 重命名为 <code>.txt</code></li></ul><h2 id="excel-数字转换为中文大写" tabindex="-1">Excel 数字转换为中文大写 <a class="header-anchor" href="#excel-数字转换为中文大写" aria-label="Permalink to &quot;Excel 数字转换为中文大写&quot;">​</a></h2><p>将数字转换为中文大写（如 <code>123</code> → <code>一百二十三</code>）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=TEXT(RIGHT(A1),&quot;[dbnum1]&quot;)</span></span></code></pre></div><h3 id="说明-1" tabindex="-1">说明 <a class="header-anchor" href="#说明-1" aria-label="Permalink to &quot;说明&quot;">​</a></h3><ul><li><code>[dbnum1]</code> 是 Excel 内置的格式化代码，用于将数字转换为中文小写数字（一、二、三...）</li><li>如果需要中文大写（壹、贰、叁...），使用 <code>[dbnum2]</code></li><li><code>RIGHT(A1)</code> 取 A1 单元格的值</li></ul><hr><h2 id="excel-筛选求和" tabindex="-1">Excel 筛选求和 <a class="header-anchor" href="#excel-筛选求和" aria-label="Permalink to &quot;Excel 筛选求和&quot;">​</a></h2><blockquote><p>来源：<a href="https://github.com/aiastia/note/issues/26" target="_blank" rel="noreferrer">#26</a></p></blockquote><p>在 Excel 中对满足特定条件的多个选项进行求和。</p><h3 id="公式" tabindex="-1">公式 <a class="header-anchor" href="#公式" aria-label="Permalink to &quot;公式&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=SUM(SUMIF(H2:H42,{&quot;需要的选项&quot;},O2:O42))</span></span></code></pre></div><h3 id="说明-2" tabindex="-1">说明 <a class="header-anchor" href="#说明-2" aria-label="Permalink to &quot;说明&quot;">​</a></h3><ul><li><code>SUMIF</code> 按条件求和，<code>{&quot;需要的选项&quot;}</code> 使用数组语法支持多个条件</li><li>外层 <code>SUM</code> 将多个条件的结果相加</li><li>例如需要同时对&quot;选项A&quot;和&quot;选项B&quot;求和：<code>=SUM(SUMIF(H2:H42,{&quot;选项A&quot;,&quot;选项B&quot;},O2:O42))</code></li></ul><h2 id="excel-中将文本公式转换为计算结果" tabindex="-1">Excel 中将文本公式转换为计算结果 <a class="header-anchor" href="#excel-中将文本公式转换为计算结果" aria-label="Permalink to &quot;Excel 中将文本公式转换为计算结果&quot;">​</a></h2><blockquote><p>来源：<a href="https://github.com/aiastia/note/issues/2" target="_blank" rel="noreferrer">#2</a></p></blockquote><p>当 A1 单元格显示的是公式文本（如 <code>15*15</code>），如何在 B1 中通过公式引用得到计算结果。</p><h3 id="方法-使用-evaluate-函数" tabindex="-1">方法：使用 EVALUATE 函数 <a class="header-anchor" href="#方法-使用-evaluate-函数" aria-label="Permalink to &quot;方法：使用 EVALUATE 函数&quot;">​</a></h3><p>Excel 没有直接在工作表中使用 <code>EVALUATE</code> 函数的方式，需要通过「定义名称」来间接调用：</p><ol><li>选中 B1 单元格</li><li>打开「插入」菜单 →「名称」→「定义」（或「公式」选项卡 →「定义名称」）</li><li>在「名称」中输入一个自定义名称，如 <code>ABCDEFG</code></li><li>在「引用位置」中输入：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=EVALUATE(Sheet1!A1)</span></span></code></pre></div><ol start="5"><li>点击确定</li><li>在 B1 中输入 <code>=ABCDEFG</code>，即可得到 A1 中公式的计算结果</li><li>选中 B1，按住右下角填充柄向下拖动即可批量计算</li></ol><h2 id="powershell-修改文件创建时间" tabindex="-1">PowerShell 修改文件创建时间 <a class="header-anchor" href="#powershell-修改文件创建时间" aria-label="Permalink to &quot;PowerShell 修改文件创建时间&quot;">​</a></h2><blockquote><p>来源：<a href="https://github.com/aiastia/note/issues/77" target="_blank" rel="noreferrer">#77</a></p></blockquote><p>使用 PowerShell 批量修改文件的创建时间：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-Item</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C:\\Users\\*\\Desktop\\*\\***.pdf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).CreationTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Get-Date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2022-01-01 10:00:00&quot;</span></span></code></pre></div><h3 id="说明-3" tabindex="-1">说明 <a class="header-anchor" href="#说明-3" aria-label="Permalink to &quot;说明&quot;">​</a></h3><ul><li><code>Get-Item</code> 获取文件对象，支持通配符路径</li><li><code>CreationTime</code> 设置文件创建时间</li><li><code>Get-Date</code> 将字符串转换为日期对象</li><li>如需修改最后修改时间，将 <code>CreationTime</code> 改为 <code>LastWriteTime</code></li><li>如需修改访问时间，将 <code>CreationTime</code> 改为 <code>LastAccessTime</code></li></ul><h3 id="其他时间属性" tabindex="-1">其他时间属性 <a class="header-anchor" href="#其他时间属性" aria-label="Permalink to &quot;其他时间属性&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 同时修改创建时间、修改时间、访问时间</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$file </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Get-Item</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C:\\path\\to\\file.pdf&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$file.CreationTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Get-Date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2022-01-01 10:00:00&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$file.LastWriteTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Get-Date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2022-01-01 10:00:00&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$file.LastAccessTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Get-Date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2022-01-01 10:00:00&quot;</span></span></code></pre></div><h3 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h3><ul><li><a href="https://zhidao.baidu.com/question/21668351.html" target="_blank" rel="noreferrer">百度知道 - 前一单元格显示公式，后一单元格如何显示结果</a></li></ul>`,41)])])}const u=e(l,[["render",h]]);export{k as __pageData,u as default};
